export async function syncProductsFromUpstream() {
  await new Promise((resolve) => setTimeout(resolve, 1500));

  products = products.map((product, index) => {
    const priceShift = (index % 2 === 0 ? 15 : -10) + index;
    const nextInventory = Math.max(0, product.inventory + 6 - index * 4);

    return {
      ...product,
      price: product.price + priceShift,
      inventory: nextInventory,
      availability:
        nextInventory === 0
          ? "Backorder"
          : nextInventory < 10
            ? "Low stock"
            : "In stock",
    };
  });

  lastSyncedAt = new Date().toISOString();
}
